import './Header.scss';

import ImageSmall from ':components/FileUploader/FileIcons/ImageSmall';
import PdfSmall from ':components/FileUploader/FileIcons/PdfSmall';
import TextSmall from ':components/FileUploader/FileIcons/TextSmall';
import { IconButton } from ':components/IconButton';
import type { PreviewProps } from ':components/Preview/Preview.types';
import { Typography } from ':components/Typography';
import { classNames } from ':helpers/classnames';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import React from 'react';

type HeaderProps = Pick<PreviewProps, 'type' | 'value' | 'onClose' | 'modal' | 'headerCustomElements'>;

export const Header = ({ type, value, onClose, modal, headerCustomElements }: HeaderProps) => (
	<div className={classNames('dsb_preview__header', modal && 'dsb_preview__header-modal')}>
		<div className="dsb_preview__header__icon">
			{type === 'pdf' ? <PdfSmall /> : type === 'docx' ? <TextSmall /> : <ImageSmall />}
		</div>
		<Typography className="dsb_preview__header__name" variant="body2">
			{value.fileName}
		</Typography>
		<div className="dsb_preview__header__actions">{headerCustomElements}</div>
		{modal && (
			<IconButton size="large" className="dsb_preview__header__close" iconName={Icons.Close} onClick={onClose} />
		)}
	</div>
);
